messages.content:
Extract data from the following document based on the JSON schema.
Return null if the document does not contain information relevant to schema.
Return only the JSON with no explanation text.
The JSON schema is as follows:
{
  "type": "object",
  "required": [
    "firstName",
    "lastName",
    "address"
  ],
  "properties": {
    "dob": {
      "type": "string",
      "description": "Patient's date of birth as it appears"
    },
    "zip": {
      "type": "string",
      "description": "Patient's ZIP code as it appears"
    },
    "phone": {
      "type": "string",
      "description": "Patient's phone number as it appears"
    },
    "state": {
      "type": "string",
      "description": "Patient's state as it appears"
    },
    "address": {
      "type": "string",
      "description": "Street address of the patient as it appears, only including number and street"
    },
    "lastName": {
      "type": "string",
      "description": "Patient's last name"
    },
    "firstName": {
      "type": "string",
      "description": "Patient's first name"
    },
    "spouseName": {
      "type": "string",
      "description": "Spouse's name"
    },
    "isNewTherapy": {
      "type": "boolean",
      "description": "Indicates if requested medicine is new, must return true or false"
    },
    "maritalStatus": {
      "emum": [
        "Single",
        "Married",
        "Divorced",
        "Separated",
        "Widowed"
      ],
      "type": "string",
      "description": "Patient's marital status"
    },
    "isHospitalized": {
      "type": "boolean",
      "description": "Indicates if patient has been hospitalized in the past year, must return true or false"
    },
    "reviewOfSymptoms": {
      "type": "object",
      "properties": {
        "fever": {
          "type": "boolean",
          "description": "Indicates if patient has experienced a fever, must return true or false"
        },
        "chills": {
          "type": "boolean",
          "description": "Indicates if patient has experienced chills, must return true or false"
        },
        "coughing": {
          "type": "boolean",
          "description": "Indicates if patient has experienced persistent coughing, must return true or false"
        },
        "seizures": {
          "type": "boolean",
          "description": "Indicates if patient has experienced seizures, must return true or false"
        },
        "allergies": {
          "type": "boolean",
          "description": "Indicates if patient has allergies, must return true or false"
        },
        "chestPain": {
          "type": "boolean",
          "description": "Indicates if patient has experienced chest pain, must return true or false"
        },
        "blurredVision": {
          "type": "boolean",
          "description": "Indicates if patient has experienced blurred vision, must return true or false"
        },
        "dentalProblems": {
          "type": "boolean",
          "description": "Indicates if patient has experienced dental problems, must return true or false"
        },
        "enlargedGlands": {
          "type": "boolean",
          "description": "Indicates if patient has experienced enlarged glands, must return true or false"
        },
        "excessiveStress": {
          "type": "boolean",
          "description": "Indicates if patient has experienced excessive stress, must return true or false"
        },
        "excessiveBruising": {
          "type": "boolean",
          "description": "Indicates if patient has experienced excessive bruising, must return true or false"
        },
        "shortnessOfBreath": {
          "type": "boolean",
          "description": "Indicates if patient has experienced shortness of breath, must return true or false"
        },
        "irregularHeartRate": {
          "type": "boolean",
          "description": "Indicates if patient has experienced an irregular heart rate, must return true or false"
        },
        "tuberculosisExposure": {
          "type": "boolean",
          "description": "Indicates if patient has been exposed to tuberculosis, must return true or false"
        },
        "stomachTroubleOrUlcers": {
          "type": "boolean",
          "description": "Indicates if patient has experienced stomach trouble or ulcers, must return true or false"
        }
      },
      "description": "Indicates if specific symptoms are present or not"
    },
    "previousHealthHistory": {
      "type": "object",
      "required": [
        "primaryCarePhysician"
      ],
      "properties": {
        "lastSeenDate": {
          "type": "string",
          "description": "Date last seen by physician"
        },
        "prescriptionDrugs": {
          "type": "object",
          "properties": {
            "other": {
              "type": "array",
              "items": {
                "type": "string"
              },
              "description": "List of other prescription drugs that patient uses, must return null if not provided"
            },
            "dietPills": {
              "type": "boolean",
              "description": "Indicates if patient uses diet pills, must return true or false"
            },
            "painPills": {
              "type": "boolean",
              "description": "Indicates if patient uses pain pills, must return true or false"
            },
            "muscleRelaxers": {
              "type": "boolean",
              "description": "Indicates if patient uses muscle relaxers, must return true or false"
            },
            "antidepressants": {
              "type": "boolean",
              "description": "Indicates if patient uses antidepressants, must return true or false"
            },
            "birthControlPills": {
              "type": "boolean",
              "description": "Indicates if patient uses birth control, must return true or false"
            },
            "bloodSugarMedication": {
              "type": "boolean",
              "description": "Indicates if patient uses blood sugar medication, must return true or false"
            }
          },
          "description": "Details of prescription drugs currently taken"
        },
        "accidentsOrInjuries": {
          "type": "array",
          "items": {
            "type": "string"
          },
          "description": "List of accidents or injuries that patient has experienced, must return null if not provided"
        },
        "overTheCounterDrugs": {
          "type": "array",
          "items": {
            "type": "string"
          },
          "description": "List of over-the-counter drugs that patient uses, must return null if not provided"
        },
        "primaryCarePhysician": {
          "type": "string",
          "description": "Name of primary care physician"
        },
        "vitaminsOrSupplements": {
          "type": "array",
          "items": {
            "type": "string"
          },
          "description": "List of vitamins or supplements that patient takes, must return null if not provided"
        }
      },
      "description": "Details of patient's previous health history"
    }
  }
}
